@echo off
echo ========================================
echo  AUDIRA-WEB-SEAL-ONLINE - Stop All
echo ========================================
echo.

echo [1/2] Stopping Docker containers...
docker-compose down
if %errorlevel% equ 0 (
    echo Docker containers stopped successfully.
) else (
    echo No Docker containers to stop or Docker not running.
)

echo.
echo [2/2] Stopping Node.js processes on ports...

REM Stop Web Portal (3000)
echo Stopping Web Portal (port 3000)...
for /f "tokens=5" %%a in ('netstat -aon ^| findstr :3000 ^| findstr LISTENING') do (
    taskkill /F /PID %%a >nul 2>&1
)

REM Stop Admin Panel (3001)
echo Stopping Admin Panel (port 3001)...
for /f "tokens=5" %%a in ('netstat -aon ^| findstr :3001 ^| findstr LISTENING') do (
    taskkill /F /PID %%a >nul 2>&1
)

REM Stop API (4000)
echo Stopping API (port 4000)...
for /f "tokens=5" %%a in ('netstat -aon ^| findstr :4000 ^| findstr LISTENING') do (
    taskkill /F /PID %%a >nul 2>&1
)

REM Stop Realtime (4001)
echo Stopping Realtime (port 4001)...
for /f "tokens=5" %%a in ('netstat -aon ^| findstr :4001 ^| findstr LISTENING') do (
    taskkill /F /PID %%a >nul 2>&1
)

REM Stop AI Service (4002)
echo Stopping AI Service (port 4002)...
for /f "tokens=5" %%a in ('netstat -aon ^| findstr :4002 ^| findstr LISTENING') do (
    taskkill /F /PID %%a >nul 2>&1
)

echo.
echo ========================================
echo  All services stopped successfully!
echo ========================================
echo.
echo Stopped:
echo   - Docker containers (PostgreSQL, Redis)
echo   - Web Portal (port 3000)
echo   - Admin Panel (port 3001)
echo   - API (port 4000)
echo   - Realtime (port 4001)
echo   - AI Service (port 4002)
echo.
pause
